// Input: multiple items from AI Agent
// Each item has { output: "```json ... ```" }

const results = [];

for (const item of $input.all()) {
  const raw = item.json.output;

  if (!raw || typeof raw !== "string") {
    throw new Error("Missing or invalid AI output");
  }

  // Remove markdown fencing
  const cleaned = raw
    .replace(/```json/g, "")
    .replace(/```/g, "")
    .trim();

  let parsed;
  try {
    parsed = JSON.parse(cleaned);
  } catch (err) {
    throw new Error(
      "JSON parsing failed: " +
        err.message +
        "\nCleaned data:\n" +
        cleaned
    );
  }

  // Push parsed JSON as its own item
  results.push({ json: parsed });
}

// Return one item per food
return results;
